var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"말루프 씨가 관리국 시니어라면… 여기 있는 민하 씨는?","JPN":"マルーフさんが管理局のシニアなら……ここにいるミウさんは？","ENG":"If you're an Administration Senior... then what about Minha here?","TWN":"如果瑪盧夫是管理局Senior……那這位敏荷是？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그라운드 원의 공인 카운터지.","JPN":"グラウンド・ワンの公認カウンターだ。","ENG":"She's Ground One's Official Counter.","TWN":"她是G1的認證制裁者。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이렇게 어린 사람이 공인 카운터라니… 처음 알았어요.","JPN":"こんな若い方が公認カウンターだなんて……知らなかったです。","ENG":"I had no idea someone so young could be an Official Counter...","TWN":"這麼年輕就是認證制裁者……我還是第一次知道。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"공인 카운터의 정체를 그곳 거주민들이 알고 있을 의무는 없으니까.","JPN":"公認カウンターの正体を市民が知る必要はないからな。","ENG":"Residents aren't obligated to know the identity of their Official Counter.","TWN":"居民本來就沒有義務知道認證制裁者的身分。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그걸 감안해도, 민하가 지금껏 그라운드 원에 얼굴을 거의 비추지 않았던 건 사실이야. 직무유기, 업무태만이지.","JPN":"とはいえ、ミウが今までグラウンド・ワンにほどんど顔を出さなかったのは事実。職務放棄、業務怠慢だ。","ENG":"Even so, it's true that Minha has barely shown her face in Ground One. Negligence. Dereliction of duty.","TWN":"即便如此，敏荷至今幾乎沒在G1露面也是事實。說她瀆職、怠惰也不為過。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"공인 카운터 자리 넘겨 받겠다고 한 적 없다 뭐. 시니어가 멋대로 떠맡겼을 뿐이야.","JPN":"公認カウンターを引き継ぐなんて一言も言ってないし。シニアが勝手に押し付けただけ。","ENG":"It's not like I ever asked to inherit the position. The Senior dumped it on me on his own.","TWN":"我可沒說過要接這個位子，是Senior擅自丟給我的。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"난 세상을 떠돌면서 사람들을 구하느라 바빴다고.","JPN":"私は世界を巡って人助けするのに忙しかったの。","ENG":"I was busy traveling the world, saving people.","TWN":"我忙著在世界各地救人。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"사람들을 구하고 다녔다고요?","JPN":"人助けをして回っていたんですか？","ENG":"Saving people?","TWN":"救人？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"민하는 위험에 처한 사람들을 구하고 감사를 받으면 희열을 느끼는 성향이거든.","JPN":"ミウは危機に陥った人を助けて感謝されることに悦びを感じるタイプでな。","ENG":"Minha has a tendency to feel exhilarated when she rescues people and receives their gratitude.","TWN":"敏荷是那種救了人後，只要收到感謝就會感到興奮的類型。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"아마 널 도와줄 때도 자기가 은인이니 감사하라느니 신나서 떠들어댔겠지. 일종의 메시아 신드롬이야.","JPN":"おそらく、あなたを助けたときも恩人だの感謝しろだの、さぞうるさかったんじゃないか？　一種の救済者願望だな。","ENG":"She probably got excited and went on about being your life-saver when she helped you, too. A sort of messiah complex.","TWN":"她幫你的時候應該也自稱恩人、一邊得意洋洋吧？算是某種救世主症候群。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"저기요, 말루프 씨. 그렇게 말하면 내가 미친■ 같잖아.","JPN":"ちょっとマルーフさん。そんな言い方したら私が変な風に思われるじゃない。","ENG":"Hey, Ms. Maalouf. When you put it like that, I sound crazy.","TWN":"喂，瑪盧夫，你這樣講我聽起來很像瘋■子欸。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그게 아니면 공인 카운터의 역할을 내팽개치고서 방방곡곡 떠돌 다른 이유라도 있나?","JPN":"なら、公認カウンターの役目を放棄し、各地を放浪している別の理由でもあるのか？","ENG":"If that's not it, then why abandon your role as Official Counter and wander all over the place?","TWN":"不然還有什麼理由，會把認證制裁者的職責丟著不管，到處亂跑？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그건…","JPN":"それは……","ENG":"That's...","TWN":"那是……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"쳇, 몰라. 맘대로 생각해.","JPN":"ちっ、勝手にそう思ってれば。","ENG":"Tch, whatever. Think what you want.","TWN":"嘖，算了。隨你怎麼想。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"앞서 말했듯이, 우리는 그라운드 원에 숨어 들어온 침입자들의 행방을 추적하고 있어.","JPN":"先程も話したが、私たちはグラウンド・ワンに忍びこんだ侵入者たちの行方を追っている。","ENG":"As I said earlier, we're tracking intruders who slipped into Ground One.","TWN":"如我所說，我們正在追查潛入G1的入侵者。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 결과, 당신이 일하는 가게에 잠입을 하게 됐고, 녀석들이 무엇을 노리는지 알게 됐지.","JPN":"その結果、あなたが働いている店にたどり着き、やつらの狙いがわかったというわけだ。","ENG":"That investigation led us to the bar where you work, and to what they're after.","TWN":"調查結果顯示，他們潛入你工作的店，也確定他們的目標。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"모모… 말씀이시죠?","JPN":"モモ……ですよね？","ENG":"You mean Momo...?","TWN":"是指……莫莫吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"對。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 모모란 아이에 대해, 알고 있는대로 설명해주면 고맙겠군.","JPN":"そのモモという子について、知っている情報を教えてくれると助かる。","ENG":"I'd appreciate it if you told us everything you know about that child.","TWN":"關於那個叫莫莫的孩子，把你知道的都說出來吧。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"모모는…","JPN":"モモは……","ENG":"Momo...","TWN":"莫莫她……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"달콤한 걸 좋아하고, 이상할 정도로 운이 나빠서 항상 가는 곳마다 문제를 일으키는 사고뭉치에요.","JPN":"甘いものが好きで、おかしいほど運が悪くて、いつも行く先々でトラブルを起こす問題児です。","ENG":"Loves sweets, and a walking disaster who has unbelievably bad luck, causing trouble wherever she goes.","TWN":"喜歡甜食，而且運氣異常的差。是個走到哪裡都會出事的麻煩製造機。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저도 그 밖의 정보는 모르고요.","JPN":"私の知っていることと言えば、それくらいです。","ENG":"That's all I really know.","TWN":"我也只知道這些。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"침입자들이 악마라고 불렀을 때, 언니는 분명 거기에 반응했지?","JPN":"侵入者たちがあの子を悪魔って呼んだとき、姉さん反応したよね？","ENG":"When the intruders called her a devil, you clearly reacted, didn't you?","TWN":"入侵者稱她為魔鬼時，你明顯有反應對吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"뭔가 숨기고 있는 게 있다면, 너무 늦기 전에 털어놓는 게 어때?","JPN":"何か隠しているんなら早めに話すことをお勧めするけどね。","ENG":"If there's something you're hiding, why not come clean before it's too late?","TWN":"如果還有隱瞞的，趁早說出來吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"처음 모모를 만났을 땐… 저도 악마일 거라 생각했어요.","JPN":"初めてモモに出会った時は……私も悪魔だと思いました。","ENG":"When I first met Momo... I thought she was a devil too.","TWN":"第一次見到莫莫時……我也以為她是魔鬼。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"장식이 아닌 진짜 뿔이 달려있었고, 악마를 찾는 펜듈럼은 그 가게에서만 반응했으니까.","JPN":"飾りじゃない本物の角が生えていたし、悪魔を指し示すペンデュラムはその店でしか反応しませんでしたから。","ENG":"She had real horns, not decorations, and the devil-detecting pendulum only reacted inside that bar.","TWN":"她有真正的角，而且尋找魔鬼的鐘擺只在那間店裡有反應。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하지만 지금은… 잘 모르겠네요.","JPN":"でも今は……よくわかりません。","ENG":"But now... I'm not sure anymore.","TWN":"但現在……我也說不上來了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그 아이가 진짜 악마인지, 설령 악마라해도 그런 악마가 제거해야 할만큼 나쁜 존재인 건지.","JPN":"あの子が本当に悪魔なのか、仮にそうだとしても、殺さねばならないほど悪しき存在なのか。","ENG":"Whether she's truly a devil, and even if she is, whether she's a devil so evil that she deserves to be eliminated.","TWN":"她到底是不是魔鬼；就算是，是否真的壞到必須被消滅。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"악마가 나쁜 존재인지 모르겠다라- 내가 아는 구마사가 입에 담을 법한 이야긴 아니군.","JPN":"悪魔が悪しき存在なのかよくわからない、か。私の知る限り、エクソシストが口にするような言葉ではないな。","ENG":"Not knowing whether devils are evil... Hardly something I'd expect to hear from an exorcist.","TWN":"不知道魔鬼到底壞不壞——這可不像我認識的驅魔師會說的話。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"만약 모모가 악마라면… 관리국은 어떤 조치를 취하게 되는 거죠?","JPN":"もしモモが悪魔なら……管理局はどうするつもりですか？","ENG":"If Momo really is a devil... what would the Administration do?","TWN":"如果莫莫真的是魔鬼……管理局會採取什麼行動？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"관리국의 적을 판가름하는 기준은 악마냐 아니냐가 아니라, 도시에 위협이 될 가능성에 달려있다.","JPN":"管理局が敵と判断する基準は、悪魔か否かではなく、都市の脅威になるか否かだ。","ENG":"The Administration doesn't judge enemies based on whether they're devils, but on whether they pose a threat to the city.","TWN":"管理局判定敵人的標準，不在於是不是魔鬼，而在於是否可能威脅城市。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"평범한 사람이건, 카운터 범죄자건, 악마건, 내 관할에서 문제를 일으켰다면 관리국 규정에 따라 대응할 뿐이지.","JPN":"普通の人間であろうが、カウンター犯罪者であろうが、ましてや悪魔であろうが。私の管轄区域で問題を起こしたなら管理局の規定に沿って対応するだけだ。","ENG":"Whether it's an ordinary civilian, a criminal Counter, or a devil, if they cause trouble in my jurisdiction, we respond according to Administration regulations.","TWN":"不論是普通人、制裁者罪犯還是魔鬼，只要在我管轄範圍內製造問題，就按規定處理。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"언니가 말하는 악마란 존재가 얼마나 위험한진 몰라도, 침입자들은 이미 그라운드 원에서 사람을 해쳤어.","JPN":"姉さんの言う悪魔ってのがどれほど危険なのかはわからないけど、侵入者たちはもうグラウンド・ワンで人を殺めた。","ENG":"I don't know how dangerous the kind of devil you're talking about is, but the intruders have already hurt people in Ground One.","TWN":"不管你口中的魔鬼有多危險，入侵者已經在G1傷害人了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"게다가 도시의 내부 지도를 확보하고, 보안 시스템을 무력화하려는 일련의 정황도 포착했지.","JPN":"それに都市内部の地図を確保して、セキュリティシステムを無力化しようとする一連の状況も捕捉されている。","ENG":"On top of that, we've detected signs they were securing internal city maps and trying to disable security systems.","TWN":"而且他們還掌握了城市內部地圖，並試圖癱瘓保安系統。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"우리가 막으려는 위협은 그런 거야.","JPN":"私たちが阻止しようとする脅威はそういう種類のものってこと。","ENG":"That's the kind of threat we're trying to stop.","TWN":"我們要阻止的，是這種威脅。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이 문제에 관여하고 싶다면 앞으로는 관리국의 지시에 따라 움직이도록 해.","JPN":"この件に関わりたいなら、これからは管理局の指示に従って動いてくれ。","ENG":"If you want to be involved in this matter, you'll follow the Administration's instructions from here on out.","TWN":"如果你想介入，就必須遵從管理局指示行動。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 밖의 개인 행동으로 우리 일에 간섭한다면 전부 위반행위로 간주할 테니 조심해라.","JPN":"それ以外の単独行動で私たちの仕事に干渉するなら、全部違反行為としてとらえるから気をつけるように。","ENG":"Any personal actions that interfere with our work will be treated as violations. Be careful.","TWN":"任何個人行動干涉調查，都會被視為違規，請務必小心。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"도움이 필요하다면 돕고 싶어요.","JPN":"お役に立てることがあるなら力になりたいです。","ENG":"If you need help, I want to help.","TWN":"如果有需要，我想幫忙。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하지만, 저한텐 그보다 중요한 일이…","JPN":"でも、私にはそれよりも大事なことが……","ENG":"But there's something even more important to me than that...","TWN":"可是對我來說，還有更重要的事……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"걱정 마. 협조하는 동안 그 모모라는 아이의 신변은 우리가 봐주도록 하지.","JPN":"案ずるな。あなたが協力してくれている間、モモという子はこちらで保護するとしよう。","ENG":"Don't worry. While you're cooperating, we'll ensure the safety of Momo.","TWN":"放心。在合作期間，我們會確保那個叫莫莫的孩子的安全。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"사방이 노출된 가게보단 훨씬 안전한 곳일 거다.","JPN":"無防備な店より遥かに安全なはずだ。","ENG":"She'll be in a far safer place than an exposed bar like that.","TWN":"比起四處暴露的店鋪，那裡安全多了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"오오- 여기가 이 몸의 새로운 아지트로구나!","JPN":"おお、ここが吾輩の新アジトか！","ENG":"Ooh... So this is my new hideout!","TWN":"喔喔—這裡就是我的新據點嗎！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L6_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"모모, 당분간 혼자 있어도 괜찮겠어요?","JPN":"モモ、しばらく一人で過ごしても大丈夫ですか？","ENG":"Momo, will you be all right on your own for a while?","TWN":"莫莫，你暫時一個人待著沒問題嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"마왕을 뭘로 보느냐? 이 몸은 잘 있을 테니 걱정 말고 다녀오거라, 니콜이여!","JPN":"魔王を何だと思っている？　吾輩のことは気にせず行って来い、ニコル！","ENG":"What do you take a Demon Lord for? I'll be fine! Go on already, Nicole!","TWN":"你把魔王當成什麼了？我會好好的。別擔心，去吧，妮可！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"어… 네.","JPN":"あ……はい。","ENG":"Ah... Sure.","TWN":"呃……好。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"왜? 막상 꼬마가 가지 말라고 보채면서 안 매달리니까 섭섭해?","JPN":"どうした？　行くなって駄々こねると思ったらそうじゃなくて寂しくなった？","ENG":"What, feeling a little disappointed now that the kid isn't clinging to you and begging you not to go?","TWN":"怎麼？那孩子沒哭著不讓你走，反而覺得失落？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아, 아뇨. 그런 건 아니에요.","JPN":"い、いいえ。そういうわけじゃなくて。","ENG":"N-no, that's not it.","TWN":"不、不是那樣的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"낯선 환경에서 지내는 건 싫어할 줄 알았는데, 좋아해서 의외네요.","JPN":"慣れない環境で過ごすのは嫌がると思ったのに、喜んでいるのが意外と思っただけです。","ENG":"I thought she'd hate staying in an unfamiliar place, so it's a surprise she likes it.","TWN":"我以為她不喜歡陌生環境，結果她看起來很開心，讓我有點意外。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그야 내가 특별한 미끼를 준비해 뒀거든.","JPN":"そりゃあ、私が特別な囮を用意しておいたからね。","ENG":"That's because I prepared a special lure.","TWN":"因為我準備了特別的誘餌。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"맛있는 간식이 잔뜩 쌓인 5층 디저트카트를 눈앞에 두고서 집에 가고 싶다고 말할 꼬맹이는 없을 걸?","JPN":"美味しいおやつがいっぱいに積まれた5段デザートカートを目の前にして、家に帰りたいって言いだす子どもなんていないよ？","ENG":"No kid is going to say they want to go home when there's a five-tier dessert cart piled high with snacks right in front of them.","TWN":"我把堆滿美食的5層甜點推車擺在眼前，哪個小鬼還會想回家？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"웩, 인삼 젤리는 싫은 것이다!","JPN":"げっ、高麗人参味のゼリーは嫌いだ！","ENG":"Blegh! Ginseng jelly is gross!","TWN":"噁，我討厭人參果凍！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"저게, 제일 맛있는 걸…!","JPN":"あいつ、あれが一番おいしいのに……！","ENG":"What?! But that's the best one...!","TWN":"那可是最好吃的……！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"크흠, 아무튼 언니가 갑자기 사라지는 것도 아니고, 맛있는 거 실컷 먹으면서 몇 밤만 자면 데리러 온다는데 마다할 이유가 있겠어?","JPN":"ごほん、とにかく。姉さんが急にいなくなるわけじゃないし、美味しいものを沢山食べながら数日過ごせば迎えに来るっていうのに、嫌がる理由はないでしょ。","ENG":"Ahem, anyway. It's not like you're vanishing without warning. If you stuff her with good food and sleep here a few nights, and come to get her after, why would she refuse?","TWN":"咳，總之你又不是突然消失，只是吃好吃的、睡幾晚就來接她，沒理由拒絕吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…그러게요. 쓸데없는 걱정이었나 봐요.","JPN":"……そうですね。心配のしすぎだったようです。","ENG":"...You're right. I guess I was worrying over nothing.","TWN":"……也是。看來是我多慮了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"가죠, 민하 씨.","JPN":"行きましょう、ミウさん。","ENG":"Let's go, Minha.","TWN":"走吧，敏荷。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"…니콜.","JPN":"……ニコル。","ENG":"...Nicole.","TWN":"……妮可。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…모모?","JPN":"……モモ？","ENG":"...Momo?","TWN":"……莫莫？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"무얼 하러가든 무사히 돌아오거라.","JPN":"何をしに行くにせよ、無事に帰って来い。","ENG":"Whatever you're doing, come back safely.","TWN":"不管去做什麼，都要平安回來。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"이 몸도 씩씩하게 기다리고 있으마.","JPN":"吾輩も元気で待っているぞ。","ENG":"I'll wait bravely too.","TWN":"我也會自立自強，在這裡等你。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"신기한 경험이었죠.","JPN":"不思議な経験でした。","ENG":"It was a strange feeling.","TWN":"真是奇妙的經驗。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"언제나 지켜줘야 하는 철부지 꼬맹이인 줄로만 알았는데.","JPN":"私が守ってあげないといけない、世間知らずの子どもだと思っていたのに。","ENG":"I always thought of her as a helpless kid I had to protect.","TWN":"我一直以為她只是個需要照顧的冒失小鬼。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"저런 듬직한 표정도 지을 줄 아는구나…","JPN":"こんな頼もしい顔もできるんですね……","ENG":"But she can make such a reassuring expression, too...","TWN":"沒想到也能露出那麼可靠的表情……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네.","JPN":"はい。","ENG":"Yes.","TWN":"是。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"걱정 말고 기다리세요, 마왕님.","JPN":"心配せずに待っていてください。魔王様。","ENG":"So wait without worry, Demon Lord.","TWN":"請安心等待吧，魔王大人。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그러고 보니 그 꼬맹이…","JPN":"そういえばあのちび……","ENG":"By the way, that kid...","TWN":"話說回來，那孩子……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"자길 마왕이라고 했었지?","JPN":"自分のこと魔王って言ったよね。","ENG":"She called herself a Demon Lord, right?","TWN":"她自稱魔王對吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저는 그 마왕의 사천왕 중 한 명이고요. 역할 놀이 같은 거죠.","JPN":"私はその魔王の四天王の一人なんです。ごっこ遊びのようなものですよ。","ENG":"I'm one of that Demon Lord's four champions. It's like role-playing.","TWN":"我是那位魔王的四天王之一，只是角色扮演而已。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그 애. 어디서 왔는지 알아?","JPN":"あの子、どこから来たかは知ってる？","ENG":"Do you know where she came from?","TWN":"你知道她從哪來的嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"지금은 출장 중이신 저희 사장님께서 데려오셨어요.","JPN":"今出張中の店長が連れてこられたそうです。","ENG":"Our boss, who's away on a trip right now, brought her.","TWN":"是我們老闆出差時帶回來的。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"어디서?","JPN":"どこから？","ENG":"From where?","TWN":"哪裡？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"글쎄요. 저도 거기까진 물어본 적이 없네요.","JPN":"さあ、そこまでは聞いてませんね。","ENG":"I'm not sure. I never asked that far.","TWN":"這我就沒問那麼清楚了。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"시니어는 협력하라고 했지만, 난 누구랑 협력하는 거 별로 안 좋아해.","JPN":"シニアに協力して当たるようにって言われたけど、私、人とチームを組むのってあんま好きじゃないから。","ENG":"The Senior told me to cooperate, but I don't really like working with others.","TWN":"雖然Senior叫我們合作，但我不太喜歡和人一起行動。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그러니까 그냥 가게로 돌아가도 돼.","JPN":"だから店に帰ってもいいよ。","ENG":"So you can just go back to the bar.","TWN":"所以你可以回店裡了。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네? 제가 말 실수라도 했나요? 왜 갑자기 그런 소릴…","JPN":"え？　私何か気を悪くされるようなこと言いました？　どうして急にそんな……","ENG":"What? Did I say something wrong? Why all of a sudden–","TWN":"咦？我說錯什麼了嗎？怎麼突然這樣……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"이건 평범한 사람이 감당할 수 있는 사건이 아니야.","JPN":"これは普通の人間に勤まる事件じゃない。","ENG":"This isn't a case an ordinary person can handle.","TWN":"這不是一般人能承受的事件。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"아무리 시니어라고 해도, 목숨을 걸린 일을 관련도 없는 남에게 얼렁뚱땅 맡길 수는 없는 거라고.","JPN":"いくらシニアでも、命の危険のある仕事を無関係な人に適当に任せるなんてダメに決まってる。","ENG":"No matter who the Senior is, they can't just casually drag an unrelated civilian into something that risks their life.","TWN":"就算是Senior，也不能把要賭上性命的事隨便丟給無關的人。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이건 남의 일이 아녜요. 모모가 그 침입자들에게 표적이 됐으니까요!","JPN":"無関係じゃありません。モモが侵入者たちに狙われたんです！","ENG":"This isn't someone else's problem. Momo was targeted by those intruders!","TWN":"這不是別人的事。莫莫已經成為入侵者的目標了！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그렇다면 저한테도 그 진상을 파헤칠 책임이 있어요.","JPN":"私にも真相をあばく責任があります。","ENG":"That means I have a responsibility to uncover the truth, too.","TWN":"所以我也有責任查清真相。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그 꼬마는 언니를 좋아하고 따르잖아.","JPN":"あの子は姉さんに懐いてるでしょ。","ENG":"That kid likes you. She follows you.","TWN":"那孩子那麼喜歡、依賴姐姐。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"좋아하는 사람의 부고 소식을 내 입으로 전하고 싶진 않아.","JPN":"そんな人の訃報を家族に伝えるのはごめんだね。","ENG":"I don't want to be the one to tell her the person she cares about is dead.","TWN":"我不想親口告訴她喜歡的人死了。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"어째서… 그런 불길한 소릴 하는 거죠?","JPN":"どうして……そんな不吉なことを言うんですか？","ENG":"Why... would you say something so ominous?","TWN":"為什麼……要說這麼不吉利的話？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그라운드 원의 침입자들, 언니가 상상하는 것보다 훨씬 위험한 조직이야.","JPN":"グラウンド・ワンの侵入者、あいつらは姉さんが思っている以上に危険な組織さ。","ENG":"The intruders in Ground One are far more dangerous than you imagine.","TWN":"G1的入侵者，比你想像的危險得多。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"2년 전, 그 배후를 파헤치던 사람들이 전부 죽었어. 그 중엔 S급 카운터도 있었고.","JPN":"2年前、背後を探っていた人は全員死んだ。その中にはS級カウンターだっていた。","ENG":"Two years ago, everyone who tried to dig into what was behind them died. That included a Grade S Counter.","TWN":"2年前，追查他們底細的人全都死了，其中還有S級制裁者。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"S급 카운터가 당했다고요?","JPN":"S級カウンターが、亡くなったんですか？","ENG":"A Grade S Counter was taken out?","TWN":"連S級制裁者都……？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"설마 그 배후가, 그때 언급한 마왕이란 존재…?","JPN":"まさかその背後にいるのが、あの時言っていた魔王という存在……？","ENG":"Then the one behind it all... That Demon Lord you mentioned before?","TWN":"難道幕後黑手，就是你剛提到的魔王……？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"맞아. 마왕 벨제부브.","JPN":"そう、魔王ベルゼブブ。","ENG":"That's right. The Demon Lord Beelzebub.","TWN":"沒錯。魔王，別西卜。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"S급 카운터뿐 아니라 세상 하나를 통째로 멸망시킬 수도 있는 괴물이지. 그런 존재를 신처럼 믿고 따르는 놈들이 어떤 꿍꿍이를 품고 그라운드 원에 발을 들인 거야.","JPN":"S級カウンターだけじゃなくて、世界一つをまるごと滅ぼすこともできる化け物よ。そんな存在を神だと信じて仕える輩が、何かを企んでグラウンド・ワンに忍び込んだ。","ENG":"A monster that could wipe out not just a Grade S Counter, but an entire world. And his followers, people who worship something like that as a god, set foot in Ground One with their own schemes.","TWN":"不只是能殺死S級制裁者，甚至能毀滅整個世界的怪物。崇拜那種存在的傢伙，帶著陰謀踏進了G1。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그러니 손 떼.","JPN":"だからここで手を引いて。","ENG":"So step away.","TWN":"所以放手吧。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"여기서부턴 관리국에게 맡기고, 언니는 조용히 숨어있다가 일상으로 돌아가.","JPN":"後のことは管理局に任せて、しばらくは身を潜めていなさい。事態が収まったら、また日常に戻るのよ。","ENG":"Leave it to the Administration from here on out, hide quietly, and return to your normal life.","TWN":"接下來交給管理局，你躲起來回歸日常。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"S급 카운터가 당할 정도라면, 민하 씨도 마찬가지로 목숨을 걸고 있는 거 아닌가요?","JPN":"S級カウンターでも手に負えないほどでしたら、ミウさんだって命を失う可能性があるんじゃないんですか？","ENG":"If even a Grade S Counter fell, then you're risking your life too, aren't you?","TWN":"如果連S級制裁者都會出事，那敏荷你不也是在玩命嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"난 그럴 각오가 되어있으니까. 우린 그 점이 다른 거야.","JPN":"私はその覚悟ができているから。そこが姉さんとの違いだね。","ENG":"I'm prepared for that. That's where you and I differ.","TWN":"我早就做好覺悟了。我們在這一點不一樣。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"언니는 그 앨 두고 죽어도 괜찮다고, 말할 수 있어?","JPN":"姉さんはあの子を置いて一人で死んでもいいって、本気で言える？","ENG":"Can you say you'd be fine with dying, leaving that kid behind?","TWN":"你能不管那孩子，說出「就算死了也無所謂」這種話嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그건…!","JPN":"それは……！","ENG":"That's...!","TWN":"那是……！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ADMIN_BOARDCAST_NPC_NULL","text":{"KOREA":"긴급 채널에 전파합니다.","JPN":"緊急チャンネルに伝えます。","ENG":"This is an emergency broadcast on the priority channel.","TWN":"緊急頻道播報。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L24_1","type":"dialog","speaker":"ADMIN_BOARDCAST_NPC_NULL","text":{"KOREA":"약 3분 전 경찰청으로부터 여덟 건의 거수자 신고가 접수. 여덟 장소 모두 침식파 반응이 관측되고 있는 것을 확인했습니다.","JPN":"約3分前、警察庁から8件の挙動不審者の申告がありました。なお8か所すべてにおいて侵食波反応が観測されていることを確認しています。","ENG":"Approximately three minutes ago, the Police Agency received eight reports of hostiles. All eight locations are showing Corruption ray readings.","TWN":"約3分鐘前，警方接獲八起舉報。八個地點皆觀測到侵蝕波反應。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ADMIN_BOARDCAST_NPC_NULL","text":{"KOREA":"현재 기동대응팀이 최초관측지점으로 이동 중입니다. 도시 피해의 최소화를 위해 송달된 좌표로 접근 가능한 관리국 전력에게 신속한 지원을 요청 드립니다.","JPN":"現在機動対応チームが第一観測地点へ移動中。都市の被害を最低限に抑えるために、送信した座標へ接近可能な管理局戦力に迅速な応援を要請します。","ENG":"Rapid response units are en route to the initial observation points. To minimize damage to the city, all available Administration forces capable of reaching the transmitted coordinates are requested to provide immediate support.","TWN":"機動應對小組正前往首次觀測地點，請可前往指定座標的管理局戰力即刻支援。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ADMIN_BOARDCAST_NPC_NULL","text":{"KOREA":"다시 전파합니다…","JPN":"繰り返します……","ENG":"I repeat...","TWN":"重複播報……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L27_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"모든 사람에겐 각자 살아갈 이유가 있잖아.","JPN":"すべての人には、それぞれ生きる理由があるでしょ。","ENG":"Everyone has their own reason to live.","TWN":"每個人，都有自己活下去的理由。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"마왕 추종자 놈들의 뒤를 캐고, 마왕까지 찾아서 조지는 게- 내가 살아가는 이유거든.","JPN":"魔王の追従者の裏を探り、魔王を探し出してぶっ倒す。それが私の生きる理由だから。","ENG":"Digging into those Demon Lord cultists, finding and smacking the Demon Lord down... is my reason.","TWN":"追查魔王追隨者，揪出魔王宰了他—就是我活下去的理由。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"내가. 살아가는 이유.","JPN":"私が、生きる理由。","ENG":"My reason for living.","TWN":"我，活下去的理由。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"이 소녀는… 살아있는 건가?","JPN":"この少女は……生きているのか？","ENG":"Is this girl... alive?","TWN":"這名少女……還活著嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"네. 저희가 도착했을 때, 마을의 유일한 생존자였습니다.","JPN":"はい、私たちが到着した時に残っていた、この村の唯一の生存者でした。","ENG":"Yes. When we arrived, she was the village's sole survivor.","TWN":"對。我們抵達時，她是村莊唯一的生還者。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"믿기지 않는군. 그렇게 많은 침식체가 휩쓸고 다녀간 곳에… 생존자라고?","JPN":"信じられないな。あの数の侵食体に襲われた場所に……生存者がいただと？","ENG":"Unbelievable. After that many C.O.s swept through the area... someone made it out alive?","TWN":"真難以置信。在那麼多侵蝕體肆虐過的地方……居然還活著？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"그 말씀처럼 기적이라고 봐야겠지요.","JPN":"まさに奇跡といえるでしょう。","ENG":"As you say, it can only be called a miracle.","TWN":"正如你所說，只能說是奇蹟了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"아이가 살아남은 데엔… 마땅한 이유가 있을 겁니다.","JPN":"この子が生き残ったのには……きっと理由があるはずです。","ENG":"There must be a reason the child survived...","TWN":"這孩子能活下來……一定有她的理由。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"그 이유를 찾아주는 것이 저희 성황청이 짊어질 소명일 테고요.","JPN":"その理由を見つけてあげるのが、私たち聖皇庁の使命かと。","ENG":"And uncovering that reason will be the mission the Holy Curia bears.","TWN":"找出那個理由，就是我們聖皇廳的使命。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};